code.C:
#include <stdio.h>
int gcd(int a, int b) { return b ? gcd(b, a % b) : a; }
int main() { int n; scanf("%d", &n); int a[n]; for (int i = 0; i < n; i++) scanf("%d", &a[i]); int count = 0; for (int i = 0; i < n; i++) { int flag = 0; for (int j = 0; j < i; j++) { if (gcd(a[i], a[j]) == 1) { flag = 1; break; } } if (!flag) count++; } printf("%d\n", count); return 0; }

