code.Java:
import java.util.Scanner;
public class Main { public static int gcd(int a, int b) { return b == 0 ? a : gcd(b, a % b); }
public static void main(String[] args) { Scanner scanner = new Scanner(System.in); int n = scanner.nextInt(); int[] a = new int[n]; for (int i = 0; i < n; i++) a[i] = scanner.nextInt(); int count = 0; for (int i = 0; i < n; i++) { boolean flag = false; for (int j = 0; j < i; j++) { if (gcd(a[i], a[j]) == 1) { flag = true; break; } } if (!flag) count++; } System.out.println(count); } }

code.Python3:
import math

def gcd(a, b):
    while b:
        a, b = b, a % b
    return a

def main():
    n = int(input())
    a = list(map(int, input().split()))
    count = 0
    for i in range(n):
        flag = False
        for j in range(i):
            if gcd(a[i], a[j]) == 1:
                flag = True
                break
        if not flag:
            count += 1
    print(count)

if __name__ == '__main__':
    main()

